#!/usr/bin/env python3
"""
Уровень 6: Настоящий учебник русского языка (1-2 класс).

Сырой текст учебника через read(). Без предобработки.
Система обучена уровням 1-2, потом читает весь учебник.

Движок НЕ менялся.
"""

from chrysaline import World, Visitor, Generator


# ════════════════════════════════════════════════════════
# read() — патчим World
# ════════════════════════════════════════════════════════

def read(self, text):
    visitor = Visitor(self)
    knows_space = False
    space_info = visitor.visit(" ")
    if space_info["found"]:
        s = space_info["siblings"]
        if "пробел" in s or "разделяет" in s or "слова" in s:
            knows_space = True
    knows_dot = False
    dot_info = visitor.visit(".")
    if dot_info["found"]:
        d = dot_info["siblings"]
        if "точка" in d or "конец" in d or "предложения" in d:
            knows_dot = True
    if knows_space:
        raw_tokens = [t for t in text.split(" ") if t]
        if knows_dot:
            tokens = []
            for t in raw_tokens:
                if t.endswith(".") and len(t) > 1:
                    tokens.append(t[:-1])
                    tokens.append(".")
                elif t == ".":
                    tokens.append(".")
                else:
                    tokens.append(t)
            sentences, current = [], []
            for t in tokens:
                if t == ".":
                    if current:
                        current.append(".")
                        sentences.append(current)
                        current = []
                else:
                    current.append(t)
            if current:
                sentences.append(current)
            for sent in sentences:
                self.feed_sentence(sent)
                self.run(1)
        else:
            self.feed_sentence(raw_tokens)
            self.run(1)
    else:
        self.feed_sentence(list(text))
        self.run(1)
    return {"knows_space": knows_space, "knows_dot": knows_dot,
            "mode": "sentences" if (knows_space and knows_dot) else
                    "words" if knows_space else "chars"}

World.read = read


# ════════════════════════════════════════════════════════
# ОБУЧЕНИЕ (уровни 1-2)
# ════════════════════════════════════════════════════════

LEVEL1 = [
    ["а", "это", "гласная", "буква"], ["о", "это", "гласная", "буква"],
    ["у", "это", "гласная", "буква"], ["и", "это", "гласная", "буква"],
    ["е", "это", "гласная", "буква"], ["ы", "это", "гласная", "буква"],
    ["к", "это", "согласная", "буква"], ["т", "это", "согласная", "буква"],
    ["м", "это", "согласная", "буква"], ["н", "это", "согласная", "буква"],
    ["р", "это", "согласная", "буква"], ["с", "это", "согласная", "буква"],
    ["л", "это", "согласная", "буква"], ["д", "это", "согласная", "буква"],
    ["б", "это", "согласная", "буква"], ["п", "это", "согласная", "буква"],
]

LEVEL2 = [
    ["слова", "складываются", "в", "предложения"],
    ["предложение", "выражает", "мысль"],
    ["в", "конце", "предложения", "ставится", "точка"],
    ["точка", "означает", "конец", "мысли"],
    ["точка", "разделяет", "предложения"],
    ["после", "точки", "начинается", "новое", "предложение"],
    ["пробел", "разделяет", "слова"],
]

BRIDGES = [
    [".", "это", "точка"], [".", "означает", "конец", "предложения"],
    [" ", "это", "пробел"], [" ", "разделяет", "слова"],
    ["пробел", "разделяет", "слова"],
]

EXAMPLES = [
    ["кот", "спал", ".", "здесь", "точка"],
    ["мама", "мыла", "раму", ".", "здесь", "точка"],
]

# ════════════════════════════════════════════════════════
# УЧЕБНИК (сырой текст)
# ════════════════════════════════════════════════════════

TEXTBOOK = """Буквы при написании: жи-ши пиши с буквой И. ча-ща пиши с буквой А. чу-щу пиши с буквой У. Безударные гласные. Если гласный в слове безударный то при письме можно допустить ошибку. Для правильного написания гласный надо проверить. Например Леса это лес. Перенос слов. Слова переносятся с одной строки на другую по слогам. При переносе нельзя одну букву оставлять на строке и нельзя одну букву переносить на другую строку. Предложения. В устной речи одно предложение от другого отделяются паузой. При письме в конце предложения ставится точка. Если задаётся вопрос то в конце предложения ставится вопросительный знак. Если предложение произносится с особенным чувством то ставится восклицательный знак. Первое слово в предложении пишется с большой буквы. Части речи. В русском языке есть слова которые отвечают на вопрос кто или что. На вопрос кто отвечают слова которые называют людей или животных. На вопрос что отвечают слова которые называют неживые предметы. В русском языке есть слова которые отвечают на вопросы какой какая какое какие. В русском языке есть слова которые отвечают на вопросы что делать что делает что делал. Родственные слова. Есть в нашем языке родственные слова в них есть общая одинаковая часть. Снег снеговик снегурочка снегокат. Сад садовый садовник. Большая буква в словах. С большой буквы всегда пишется первое слово в предложении. С большой буквы пишутся имена отчества фамилии людей клички животных. С большой буквы пишутся названия городов улиц стран морей рек озёр. Все такие слова называют именами собственными. Существительное это самостоятельная часть речи которая обозначает предмет и отвечает на вопросы кто или что. Имена собственные обозначают имена фамилии отчества людей клички животных названия городов рек морей океанов. Существительные делятся по числам. Различают единственное и множественное число. Существительные делятся по родам. Существительные к которым можно подставить слова он мой относятся к мужскому роду. Существительные к которым можно подставить слова она моя относятся к женскому роду. Существительные к которым можно подставить слова оно моё относятся к среднему роду. Глагол это самостоятельная часть речи которая обозначает действие предмета и отвечает на вопросы что делает что делают что будет делать что сделал что сделают. Глаголы изменяются по родам. По числам. По временам. Не с глаголами пишется отдельно. Прилагательное это самостоятельная часть речи которая обозначает признак предмета и отвечает на вопросы какой какая какое какие. Местоимение это часть речи которая употребляется вместо имени существительного. Личные местоимения я ты он она оно мы вы они. Предлог это часть речи. Предлоги служат для связи слов в предложении. Состав слова. Слова состоят из приставки корня суффикса и окончания. Корень это общая часть однокоренных слов. Приставка это часть слова которая стоит перед корнем и служит для образования новых слов. Суффикс это часть слова которая стоит после корня и служит для образования новых слов. Окончание это изменяемая часть слова. Предложение это слово или несколько слов которые выражают законченную мысль. Слова в предложении связаны между собой по смыслу. Подлежащее это главный член предложения который обозначает предмет речи и отвечает на вопросы кто что. Сказуемое это главный член предложения обозначает то что говорится о предмете речи. Синонимы это слова которые произносятся по-разному а по смыслу одинаковые или очень близкие. Антонимы это слова противоположные по значению."""


def teach(world, data, label, repeats=3):
    print(f"\n  ── {label} ({len(data)} фраз, {repeats}x) ──")
    for r in range(repeats):
        for phrase in data:
            world.feed_sentence(phrase)
            world.run(1)
    alive = sum(1 for c in world.creatures.values() if c.alive)
    abst = sum(1 for c in world.creatures.values() if c.alive and c.slot_options)
    print(f"    → {alive} существ, {abst} абстракций")


def main():
    print("=" * 60)
    print("  УРОВЕНЬ 6: НАСТОЯЩИЙ УЧЕБНИК")
    print("  Русский язык 1-2 класс. Сырой текст через read().")
    print("  Движок НЕ менялся.")
    print("=" * 60)

    world = World()
    visitor = Visitor(world)
    gen = Generator(world)

    # ════════════════════════════════════════
    # ЭТАП 1: Обучение (уровни 1-2)
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 1: ОБУЧЕНИЕ")
    print("=" * 60)

    teach(world, LEVEL1, "Буквы")
    teach(world, LEVEL2, "Пунктуация")
    teach(world, BRIDGES, "Мосты", repeats=5)
    teach(world, EXAMPLES, "Примеры")

    alive0 = sum(1 for c in world.creatures.values() if c.alive)
    abst0 = sum(1 for c in world.creatures.values() if c.alive and c.slot_options)
    print(f"\n  После обучения: {alive0} существ, {abst0} абстракций")

    # ════════════════════════════════════════
    # ЭТАП 2: Учебник через read()
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 2: ЧИТАЕМ УЧЕБНИК")
    print("=" * 60)

    print(f"  Текст: {len(TEXTBOOK)} символов")
    # Считаем предложения (приблизительно)
    sent_count = TEXTBOOK.count(".")
    print(f"  Примерно {sent_count} предложений")

    absorbed_before = world.stats["absorbed"]
    result = world.read(TEXTBOOK)
    print(f"\n  read() mode: {result['mode']}")

    alive1 = sum(1 for c in world.creatures.values() if c.alive)
    abst1 = sum(1 for c in world.creatures.values() if c.alive and c.slot_options)
    absorbed1 = world.stats["absorbed"] - absorbed_before
    print(f"  После учебника: {alive1} существ, {abst1} абстракций, {absorbed1} поглощений")

    # ════════════════════════════════════════
    # ЭТАП 3: Проверка — что система поняла?
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 3: ПРОВЕРКА")
    print("=" * 60)

    checks = []

    # --- Жи-ши ---
    print(f"\n  ── Жи-ши ──")
    r1 = gen.ask("как пишется жи?")
    ok1 = "И" in r1["answers"] or "и" in r1["answers"] or "буквой" in r1["answers"]
    print(f"  1. жи пишется? → {r1['answers'][:8]}  {'OK' if ok1 else 'MISS'}")
    checks.append(("жи пишется с буквой И", ok1))

    ji_info = visitor.visit("жи-ши")
    if ji_info["found"]:
        print(f"     visit('жи-ши') братья: {sorted(ji_info['siblings'])[:10]}")

    # --- Части речи ---
    print(f"\n  ── Части речи ──")
    r2 = gen.ask("что такое существительное?")
    ok2 = "часть" in r2["answers"] or "речи" in r2["answers"] or "предмет" in r2["answers"]
    print(f"  2. существительное? → {r2['answers'][:8]}  {'OK' if ok2 else 'MISS'}")
    checks.append(("существительное → часть речи/предмет", ok2))

    r3 = gen.ask("что такое глагол?")
    ok3 = "часть" in r3["answers"] or "речи" in r3["answers"] or "действие" in r3["answers"]
    print(f"  3. глагол? → {r3['answers'][:8]}  {'OK' if ok3 else 'MISS'}")
    checks.append(("глагол → часть речи/действие", ok3))

    r4 = gen.ask("что такое прилагательное?")
    ok4 = "часть" in r4["answers"] or "признак" in r4["answers"]
    print(f"  4. прилагательное? → {r4['answers'][:8]}  {'OK' if ok4 else 'MISS'}")
    checks.append(("прилагательное → часть речи/признак", ok4))

    # --- Предложение ---
    print(f"\n  ── Предложение ──")
    r5 = gen.ask("что такое предложение?")
    ok5 = "мысль" in r5["answers"] or "слово" in r5["answers"] or "законченную" in r5["answers"]
    print(f"  5. предложение? → {r5['answers'][:8]}  {'OK' if ok5 else 'MISS'}")
    checks.append(("предложение → мысль/слово", ok5))

    r6 = gen.ask("что ставится в конце предложения?")
    ok6 = "точка" in r6["answers"] or "." in r6["answers"]
    print(f"  6. в конце предложения? → {r6['answers'][:8]}  {'OK' if ok6 else 'MISS'}")
    checks.append(("в конце предложения → точка", ok6))

    # --- Подлежащее/сказуемое ---
    print(f"\n  ── Подлежащее/сказуемое ──")
    r7 = gen.ask("что такое подлежащее?")
    ok7 = "член" in r7["answers"] or "главный" in r7["answers"] or "предмет" in r7["answers"]
    print(f"  7. подлежащее? → {r7['answers'][:8]}  {'OK' if ok7 else 'MISS'}")
    checks.append(("подлежащее → главный член", ok7))

    # --- Состав слова ---
    print(f"\n  ── Состав слова ──")
    r8 = gen.ask("что такое корень?")
    ok8 = "часть" in r8["answers"] or "общая" in r8["answers"] or "однокоренных" in r8["answers"]
    print(f"  8. корень? → {r8['answers'][:8]}  {'OK' if ok8 else 'MISS'}")
    checks.append(("корень → общая часть", ok8))

    # --- Большая буква ---
    print(f"\n  ── Большая буква ──")
    r9 = gen.ask("что пишется с большой буквы?")
    ok9 = any(w in r9["answers"] for w in ["имена", "фамилии", "города", "первое", "названия", "слово"])
    print(f"  9. большая буква? → {r9['answers'][:8]}  {'OK' if ok9 else 'MISS'}")
    checks.append(("большая буква → имена/города/первое", ok9))

    # --- Синонимы/антонимы ---
    print(f"\n  ── Синонимы/антонимы ──")
    r10 = gen.ask("что такое синонимы?")
    ok10 = "слова" in r10["answers"] or "одинаковые" in r10["answers"] or "близкие" in r10["answers"]
    print(f"  10. синонимы? → {r10['answers'][:8]}  {'OK' if ok10 else 'MISS'}")
    checks.append(("синонимы → слова одинаковые/близкие", ok10))

    # ════════════════════════════════════════
    # ЭТАП 4: Visiting — что знают ключевые понятия?
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 4: VISITING — КЛЮЧЕВЫЕ ПОНЯТИЯ")
    print("=" * 60)

    key_words = ["существительное", "глагол", "прилагательное", "предложение",
                 "подлежащее", "сказуемое", "корень", "приставка", "суффикс"]

    for word in key_words:
        info = visitor.visit(word)
        if info["found"]:
            sibs = sorted(info["siblings"])[:12]
            print(f"  '{word}' братья: {sibs}")
        else:
            print(f"  '{word}' не найден")

    # ════════════════════════════════════════
    # ЭТАП 5: Абстракции из учебника
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 5: АБСТРАКЦИИ ИЗ УЧЕБНИКА")
    print("=" * 60)

    # Ключевые абстракции
    content_words = {"это", "часть", "речи", "которая", "обозначает", "отвечает",
                     "вопросы", "предмет", "действие", "признак", "слова",
                     "пишется", "буквой", "пишутся", "большой", "буквы",
                     "предложение", "предложения", "слово", "член", "главный",
                     "корень", "суффикс", "приставка", "окончание"}

    print(f"\n  Содержательные абстракции:")
    count = 0
    for c in world.show_abstractions():
        if not (set(c.parts) & content_words):
            continue
        slots = {}
        for sn, opts in c.slot_options.items():
            clean = sorted(o for o in opts if not o.startswith("$"))
            if clean:
                slots[sn] = clean[:12]
        if slots:
            print(f"    {c.name:55s} {slots}  fed={c.times_fed}")
            count += 1
            if count >= 30:
                break

    # Абстракции "$0 это $1 часть речи"
    print(f"\n  Абстракции 'это ... часть речи':")
    for c in world.creatures.values():
        if not c.alive or not c.slot_options:
            continue
        if "это" in c.parts and "часть" in c.parts and "речи" in c.parts:
            slots = {}
            for sn, opts in c.slot_options.items():
                clean = sorted(o for o in opts if not o.startswith("$"))
                if clean:
                    slots[sn] = clean
            if slots:
                print(f"    {c.name}  {slots}  fed={c.times_fed}")

    # Абстракции "$0 пишется с буквой $1"
    print(f"\n  Абстракции 'пишется с буквой':")
    for c in world.creatures.values():
        if not c.alive or not c.slot_options:
            continue
        if "пишется" in c.parts and "буквой" in c.parts:
            slots = {}
            for sn, opts in c.slot_options.items():
                clean = sorted(o for o in opts if not o.startswith("$"))
                if clean:
                    slots[sn] = clean
            if slots:
                print(f"    {c.name}  {slots}  fed={c.times_fed}")

    # Абстракции "$0 это часть слова"
    print(f"\n  Абстракции 'это часть слова':")
    for c in world.creatures.values():
        if not c.alive or not c.slot_options:
            continue
        if "часть" in c.parts and "слова" in c.parts:
            slots = {}
            for sn, opts in c.slot_options.items():
                clean = sorted(o for o in opts if not o.startswith("$"))
                if clean:
                    slots[sn] = clean
            if slots:
                print(f"    {c.name}  {slots}  fed={c.times_fed}")

    # ════════════════════════════════════════
    # ЭТАП 6: Статистика
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("  ЭТАП 6: СТАТИСТИКА")
    print("=" * 60)

    alive_f = sum(1 for c in world.creatures.values() if c.alive)
    abst_f = sum(1 for c in world.creatures.values() if c.alive and c.slot_options)
    print(f"  Существ: {alive_f}")
    print(f"  Абстракций: {abst_f}")
    print(f"  Поглощений: {world.stats['absorbed']}")
    print(f"  Скрещиваний: {world.stats['crossbred']}")
    print(f"  Абстракций/существ: {abst_f/alive_f:.2f}")
    print(f"  Статистика: {world.stats}")

    # ════════════════════════════════════════
    # ИТОГ
    # ════════════════════════════════════════
    print(f"\n{'='*60}")
    print("╔═══════════════════════════════════════════════════════╗")
    print("║     ИТОГ: УРОВЕНЬ 6 — НАСТОЯЩИЙ УЧЕБНИК              ║")
    print("╠═══════════════════════════════════════════════════════╣")

    passed = 0
    for name, ok in checks:
        s = "+" if ok else "-"
        if ok:
            passed += 1
        print(f"║  {s} {name:52s}║")

    print(f"╠═══════════════════════════════════════════════════════╣")
    print(f"║  Результат: {passed}/{len(checks)}                                   ║")
    print(f"║  Существ: {alive_f}, абстракций: {abst_f}                   ║")
    print(f"╠═══════════════════════════════════════════════════════╣")

    if passed >= 8:
        print(f"║  УЧЕБНИК УСВОЕН.                                     ║")
    elif passed >= 5:
        print(f"║  ЧАСТИЧНО. Основные понятия усвоены.                 ║")
    elif passed >= 3:
        print(f"║  МИНИМАЛЬНО. Что-то усвоилось.                       ║")
    else:
        print(f"║  НУЖНА ДОРАБОТКА.                                    ║")

    print(f"║  Движок НЕ менялся.                                   ║")
    print(f"╚═══════════════════════════════════════════════════════╝")


if __name__ == "__main__":
    main()
